/**
 * std-vehicle — std-vehicle — fleet vehicle primitive. Lists vehicles in `browsing` with fleet stats + map view; opens vehicle detail in `viewing_single` (VIN, plate, make/model, odometer, status, driver) with Assign Driver / Maintenance / Retire actions.
 *
 * Autogenerated by scripts/regenerate-std-ts.mjs from
 * packages/almadar-std/behaviors/registry/atoms/std-vehicle.orb.
 *
 * This is a thin descriptor layer over the canonical .orb. The exported
 * functions return TraitReference / PageRefObject / OrbitalDefinition
 * payloads that reference the sibling .orb via `uses:` + `ref:`. The
 * compiler's inline phase materialises the real trait at build time.
 *
 * Do not hand-edit — regenerate via
 *   node scripts/regenerate-std-ts.mjs --only=std-vehicle
 *
 * @level atom
 * @packageDocumentation
 */

import type { TraitReference, PageRefObject, OrbitalDefinition, Entity, EntityField, EntityPersistence, TraitConfig, TraitFieldRef, EntityRow, SExpr, TraitEventListener, Trait, StateMachine } from '@almadar/core/types';
import type { MakeTraitRefOpts } from '@almadar/core/builders';
import { makeTraitRef, makePageRef, makeOrbitalWithUses } from '@almadar/core/builders';

const BEHAVIOR_PATH = 'std/behaviors/std-vehicle';
const ALIAS = 'Vehicle';

/**
 * Closed set of event keys this trait recognises —
 * derived from the .orb's `stateMachine.events[]` block
 * (transition triggers + emit names). Use as the key type
 * when passing an `events:` rename map at the call site.
 */
export type StdVehicleEventKey = 'ASSIGN_DRIVER' | 'CLOSE_VEHICLE' | 'INIT' | 'MARK_MAINTENANCE' | 'OPEN_VEHICLE' | 'RETIRE' | 'VehicleLoadFailed' | 'VehicleLoaded';

/**
 * Payload shape for the `OPEN_VEHICLE` event.
 */
export interface StdVehicleOpenVehiclePayload {
  id: string;
  row?: {
    id: string;
    vin: string;
    licensePlate: string;
    make?: string;
    model?: string;
    year?: number;
    vehicleType?: string;
    odometer?: number;
    fuelType?: string;
    status?: string;
    assignedDriverId?: string;
    pendingId?: string;
  };
}

/**
 * Payload shape for the `ASSIGN_DRIVER` event.
 */
export interface StdVehicleAssignDriverPayload {
  id: string;
}

/**
 * Payload shape for the `MARK_MAINTENANCE` event.
 */
export interface StdVehicleMarkMaintenancePayload {
  id: string;
}

/**
 * Payload shape for the `RETIRE` event.
 */
export interface StdVehicleRetirePayload {
  id: string;
}

/**
 * Payload shape for the `VehicleLoaded` event.
 */
export interface StdVehicleVehicleLoadedPayload {
  data?: EntityRow[];
  totalCount?: number;
}

/**
 * Payload shape for the `VehicleLoadFailed` event.
 */
export interface StdVehicleVehicleLoadFailedPayload {
  error?: string;
  code?: string;
}

/**
 * Typed call-site config block for this trait — every
 * field maps to a `config { ... }` entry in the source
 * .lolo. The agent fills these to specialise the trait
 * without modifying its state-machine topology.
 */
export interface StdVehicleConfig {
  /** Default: `"Fleet"` */
  title?: string;
}

/**
 * Params for the std-vehicle descriptor helpers.
 *
 * `entityName` binds every trait/page reference's `linkedEntity`.
 * The optional override fields mirror TraitReference / PageRefObject
 * fields and are forwarded to `makeTraitRef` / `makePageRef`.
 */
export interface StdVehicleParams {
  entityName: string;
  /** Extra fields to add to the orbital-scoped entity clone. */
  fields?: EntityField[];
  /** Entity persistence mode. Defaults to `persistent` when omitted.
   *  See @almadar/core EntityPersistence: persistent | runtime | singleton | instance | local. */
  persistence?: EntityPersistence;
  /** Rename the inlined trait at the call site. */
  traitName?: string;
  /** Per-key event rename map. Keys narrow to the trait's declared emit names. */
  events?: Partial<Record<StdVehicleEventKey, string>>;
  /** Per-event effect replacement (keys are POST-rename event names). */
  effects?: Record<string, SExpr[]>;
  /** Replace the imported trait's `listens` array entirely. */
  listens?: TraitEventListener[];
  /** Set every emit's scope. */
  emitsScope?: 'internal' | 'external';
  /** Typed call-site config block — see the per-field interface. */
  config?: StdVehicleConfig;
  /** URL path override for the (first) page. */
  pagePath?: string;
}

/** Trait descriptor: `Vehicle.traits.VehicleFleet`. */
export function stdVehicleTrait(params: StdVehicleParams): TraitReference {
  return makeTraitRef({
    from: BEHAVIOR_PATH,
    ref: `${ALIAS}.traits.VehicleFleet`,
    linkedEntity: params.entityName,
    ...(params.traitName !== undefined ? { name: params.traitName } : {}),
    ...(params.events !== undefined ? { events: params.events as Record<string, string> } : {}),
    ...(params.effects !== undefined ? { effects: params.effects } : {}),
    ...(params.listens !== undefined ? { listens: params.listens } : {}),
    ...(params.emitsScope !== undefined ? { emitsScope: params.emitsScope } : {}),
    ...(params.config !== undefined ? { config: params.config as TraitConfig } : {}),
  });
}

/** Page descriptor: `Vehicle.pages.VehiclePage`. */
export function stdVehiclePage(params: StdVehicleParams): PageRefObject {
  return makePageRef({
    from: BEHAVIOR_PATH,
    ref: `${ALIAS}.pages.VehiclePage`,
    ...(params.pagePath !== undefined ? { path: params.pagePath } : {}),
    linkedEntity: params.entityName,
  });
}

/** Whole-orbital descriptor. */
export function stdVehicle(params: StdVehicleParams): OrbitalDefinition {
  const entity: Entity = {
    name: params.entityName,
    fields: params.fields ?? [],
    ...(params.persistence !== undefined ? { persistence: params.persistence } : {}),
  };
  return makeOrbitalWithUses({
    name: 'VehicleOrbital',
    uses: [{ from: BEHAVIOR_PATH, as: ALIAS }],
    entity,
    traits: [
      stdVehicleTrait(params),
    ],
    pages: [
      stdVehiclePage(params),
    ],
  });
}
